import{c as t,a7 as r,y as n,B as i,v as a,D as e}from"./chunks/framework.3cjvm90C.js";const g=JSON.parse('{"title":"VDN 价值分解网络","description":"介绍 VDN 如何通过加性分解实现多智能体协作学习","frontmatter":{"title":"VDN 价值分解网络","description":"介绍 VDN 如何通过加性分解实现多智能体协作学习"},"headers":[],"relativePath":"rlwiki/papers/vdn.md","filePath":"rlwiki/papers/vdn.md","lastUpdated":1782448598000}'),p={name:"rlwiki/papers/vdn.md"};function o(s,l,h,_,m,d){return r(),n("div",null,[...l[0]||(l[0]=[i('<h1 id="vdn-合作模式下多智能体学习的价值分解网络" tabindex="-1">VDN （合作模式下多智能体学习的价值分解网络） <a class="header-anchor" href="#vdn-合作模式下多智能体学习的价值分解网络" aria-label="Permalink to “VDN （合作模式下多智能体学习的价值分解网络）”">​</a></h1><ul><li><em>论文链接： <a href="https://arxiv.org/pdf/1706.05296.pdf" target="_blank" rel="noreferrer">https://arxiv.org/pdf/1706.05296.pdf</a></em></li><li><em>实现代码： <a href="https://github.com/oxwhirl/pymarl" target="_blank" rel="noreferrer">https://github.com/oxwhirl/pymarl</a></em></li></ul><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to “背景”">​</a></h2><p>多智能体强化学习的传统解决方案有两种：</p><ul><li>集中式：通过将各个智能体的状态空间与动作空间组合为联合状态空间与联合动作空间进行集中式训练，将多智能体训练视为单智能体训练</li><li>独立式：每个智能体使用单智能体的方法独立训练, 不做通信，也不做配合。</li></ul><p>这两种方法各自具有缺陷：</p><ul><li>集中式的方法在训练两个智能体时往往会产生”lazy agent ”的问题，即只有一个智能体活跃，而另一个变得很懒。这是因为当一个智能体学到有效的策略后，另一个智能体会因为不想干扰已经学好的智能体的策略导致整个团队的收益降低，从而不愿意学习。</li><li>独立式的方法在训练时很困难，在许多简单环境中都没有效果。因为每个智能体面对的环境是动态的（另一个智能体的行为成为了环境中的动态部分），而且每个智能体可能会收到由其他智能体执行且自己观察不到的动作所产生的假的奖励信号。</li></ul><p>为了解决现有两类方法的缺陷， VDN 中提出提出了值函数分解的方法，通过 learning 的方式将团队整体奖励中分解为每个智能体自己的奖励。一种通过反向传播将团队的奖励信号分解到各个智能体上的方式。</p><h2 id="q-函数值分解" tabindex="-1">Q 函数值分解 <a class="header-anchor" href="#q-函数值分解" aria-label="Permalink to “Q 函数值分解”">​</a></h2><p>如果想要使用基于价值的强化学习模型（value-based），就需要对系统的联合动作-价值函数（joint action-value function，联合 Q 函数）建模。假设系统中有 d 个智能体，则联合 Q 函数可以表示为 $Q((h1,h2,…,hd),(a1,a2,…,ad))$，其中 hi 表示智能体的局部信息， ai 表示动作。可以看出，如果使用一般的方法建模， Q 函数的输出维度是 dn， n 是动作空间的维度。</p><p>Value-Decomposition Networks （VDN）的基本假设是，系统的联合 Q 函数可以近似为多个单智能体的 Q 函数的和：$Q\\left(\\left(h^{1}, h^{2}, \\ldots, h^{d}\\right),\\left(a^{1}, a^{2}, \\ldots, a^{d}\\right)\\right) \\approx \\sum_{i=1}^{d} \\tilde{Q}_{i}\\left(h^{i}, a^{i}\\right)$</p><p>其中 Qi 之间是独立的，只取决于局部观策和动作 hi,ai。这样可以保证，最大化每个单智能体的 $Q̃_i$函数得到动作，与通过最大化联合 Q 函数得到的结果是一样的，即</p>',12),a("p",null,[e("$$\\begin{array}{c}{\\max_{a} Q=\\max_{a} \\sum_{i=1}^{d} \\tilde{Q}"),a("em",{i:"1"},"{i}=\\sum"),e("^{d} \\max_{a_{i} } \\tilde{Q}"),a("em",{a:""},"{i} } \\ {\\operatorname{argmax}"),e(" Q=\\left(\\operatorname{argmax}"),a("em",{i:""},"{a"),e(" } \\tilde{Q}_{i}\\right)}\\end{array}$$")],-1),a("p",null,"我们可以通过全局的奖励函数，间接地训练每个单智能体的 Q 函数。并且只要对每个智能体选择最大化$Q̃_i$的动作，就能使得全局 Q 值最大。",-1),a("p",null,"其网络结构如下图所示：",-1),a("p",null,[a("img",{src:"https://img-blog.csdnimg.cn/20210527093123262.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dlaXhpbl8zOTA1OTAzMQ==,size_1,color_FFFFFF,t_70#pic_center",alt:"img"})],-1),a("p",null,"先看上图中的图 1，画的是两个独立的智能体，因为对每个智能体来说，观测都是部分可观测的，所以 Q 函数是被定义成基于观测历史数据所得到的$Q\\left(h_{t}, a_{t}\\right)$，实际操作的时候直接用 RNN 来做就可以。",-1),a("p",null,"图 2 说的就是联合动作值函数由各个智能体的值函数累加得到的：$Q\\left(\\left(h^{1}, h^{2}, \\ldots, h^{d}\\right),\\left(a^{1}, a^{2}, \\ldots, a^{d}\\right)\\right) \\approx \\sum_{i=1}^{d} \\tilde{Q}_{i}\\left(h^{i}, a^{i}\\right)$",-1),a("p",null,[e("其中 d 表示 d 个智能体，$\\tilde{Q}"),a("em",{i:""},"{i}$由每个智能体的局部观测信息得到，$ \\tilde{Q}"),e(" $是通过联合奖励信号反向传播到各个智能体的 $\\tilde{Q}_{i} $上进行更新的。这样各个智能体通过贪婪策略选取动作的话，也就会使得联合动作值函数最大。")],-1),i('<p>总结来说：值分解网络旨在学习一个联合动作值函数 $$Q_{t o t}(\\tau, \\mathbf{u})$$，其中 $ \\tau \\in \\mathbf{T} \\equiv \\mathcal{T}$ 是一个联合动作-观测的历史轨迹， u 是一个联合动作。它是由每个智能体 a 独立计算其值函数 $Q_{a}\\left(\\tau^{a}, u^{a} ; \\theta^{a}\\right)$，之后累加求和得到的。其关系如下所示：$$Q_{t o t}(\\tau, \\mathbf{u})=\\sum_{i=1}^{n} Q_{i}\\left(\\tau^{i}, u^{i} ; \\theta^{i}\\right)$$</p><p>严格意义上说 $Q_{a}$称作值函数可能不太准确，因为并没有理论依据表明一定存在一个 reward 函数，使得该 $Q~i $ 满足贝尔曼方程。</p><h2 id="参数共享" tabindex="-1">参数共享 <a class="header-anchor" href="#参数共享" aria-label="Permalink to “参数共享”">​</a></h2><p>使用以下的技巧， VDN 能够得到更好的效果：</p><ul><li>使用 DRQN 作为 Q 函数。DRQN 是一个用来处理 POMDP （部分可观马尔可夫决策过程）的一个算法，其采用 LSTM 替换 DQN 卷基层后的一个全连接层，来达到能够记忆历史状态的作用，因此可以在部分可观的情况下提高算法性能。经试验证明，使用 LSTM 作为 Q 函数网络的输出层在 PODMP 环境下有更强的鲁棒性和泛化能力。</li><li>参数共享（weight sharing）和角色信息（role information）。即所有的单智能体使用同一个 Q 函数网络，同时在输入中加入一个 one-hot 向量来区别不同角色的智能体。</li><li>智能体间的通信（information channels）。本文试验了两种通信方式，一种是在输入时就包括了其他智能体的信息（low level），另一种是结合 Q 网络的高层隐藏变量（high level）再分别输出。</li></ul><h2 id="实验" tabindex="-1">实验 <a class="header-anchor" href="#实验" aria-label="Permalink to “实验”">​</a></h2><p>实验对比了不同训练方式（集中训练分步执行、集中式、独立式）和不同通信方式（VDN,VDN+low level,VDN+high level 的网络结构）的效果。不同网络结构中在 low level 做通信的结构学习速度比在 high level 通信更快。集中训练分步执行效果好于传统方式。三种通信方式结构如下图所示：</p><ul><li>值分解的独立的智能体网络结构可以参考下图所示：</li></ul><p><img src="https://img-blog.csdnimg.cn/20210527103005830.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dlaXhpbl8zOTA1OTAzMQ==,size_1,color_FFFFFF,t_70#pic_center" alt="img"></p><ul><li>如果在此基础上在加上底层的通信的话可以表示为如下形式(其实就是将各个智能体的观测给到所有的智能体)：</li></ul><p><img src="https://img-blog.csdnimg.cn/20210527103111397.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dlaXhpbl8zOTA1OTAzMQ==,size_1,color_FFFFFF,t_70#pic_center" alt="img"></p><ul><li>如果是在高层做通信的话可以得到如下形式：</li></ul><p><img src="https://img-blog.csdnimg.cn/20210527103321579.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dlaXhpbl8zOTA1OTAzMQ==,size_1,color_FFFFFF,t_70#pic_center" alt="img"></p><ul><li>如果是在底层加上高层上都做通信的话可以得到如下形式：</li></ul><p><img src="https://img-blog.csdnimg.cn/20210527103702795.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dlaXhpbl8zOTA1OTAzMQ==,size_1,color_FFFFFF,t_70#pic_center" alt="img"></p><ul><li>如果是集中式的结构的话，可以表示为如下形式：</li></ul><p><img src="https://img-blog.csdnimg.cn/20210527103513555.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dlaXhpbl8zOTA1OTAzMQ==,size_1,color_FFFFFF,t_70#pic_center" alt="img"></p><h2 id="缺点" tabindex="-1">缺点 <a class="header-anchor" href="#缺点" aria-label="Permalink to “缺点”">​</a></h2>',18),a("ul",null,[a("li",null,"多智能体实验环境简单"),a("li",null,"对于一些比较大规模的多智能体优化问题，它的学习能力将会大打折扣。其根本限制在于缺少值函数分解有效性的理论支持。"),a("li",null,[e("VDN 可行的原因可以总结为一个公式：$\\operatorname{argmax}"),a("em",{"a_{i":""},"{a} Q=\\left(\\operatorname{argmax}"),e(" } \\tilde{Q}_{i}\\right)$。VDN 中联合函数的表达形式（求和）满足这个条件，但求和这种方式表现力有限，并不能涵盖更加复杂的组合情况，比如非线性组合。")])],-1),i('<h2 id="优点" tabindex="-1">优点 <a class="header-anchor" href="#优点" aria-label="Permalink to “优点”">​</a></h2><ul><li><p>VDN 算法结构简洁，设计了中心化计算系统的 Q 函数，去中心化的单智能体 Qi 函数。同时每个智能体</p></li><li><p>这种结构使得在训练的时候可以利用全局信息， 能够在一定程度上保证整体 Q 函数的最优性。通过它分解得到的 $Q_i $可以让智能体，根据自己的局部观测选择贪婪动作，从而执行分布式策略。</p></li><li><p>VDN 的端到端训练和参数共享使得算法收敛速度非常快，针对一些简单的任务，该算法可以说既快速又有效。</p></li></ul><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to “Reference”">​</a></h2><ul><li><a href="https://arxiv.org/pdf/1706.05296.pdf" target="_blank" rel="noreferrer">Value-Decomposition Networks For Cooperative Multi-Agent Learning Based On Team Reward, AAMAS 2018</a></li></ul>',4)])])}const u=t(p,[["render",o]]);export{g as __pageData,u as default};
